class Solution {
    public int peopleAwareOfSecret(int n, int delay, int forget) {
        final int MOD = (int) 1e9 + 7;
        int[] dp = new int[n + 1];
        dp[1] = 1;
        int share = 0, aware = 1;
        for (int i = 2; i <= n; i++) {
            if (i > forget) {
                aware -= dp[i - forget];
            }
            if (i > delay) {
                share += dp[i - delay];
            }
            dp[i] = share;
            aware += dp[i];
            aware %= MOD;
            share %= MOD;
        }
        return aware % MOD;
    }
}
